// ============================================================
// NODO 1 — VALIDACIÓN Y EXTRACCIÓN DE METADATOS IFC
// Cumplimiento: buildingSMART IFC 4.3 (ISO 16739-1:2024)
// ============================================================

const item = $input.item;
const body = item.json.body || {};
const headers = item.json.headers || {};

// ─── 1. Detectar archivo ─────────────────────────────────────
const contentType = headers['content-type'] || '';
if (!contentType.includes('multipart/form-data')) {
  throw new Error('Content-Type debe ser multipart/form-data');
}

// Obtener metadatos del form
const projectName = body.project_name || 'Sin nombre';
const description = body.description || '';
const discipline = body.discipline || 'Arquitectura';
const phase = body.phase || 'Diseño';
const uploadedBy = body.uploaded_by || 'Desconocido';

// ─── 2. Simular extracción de cabecera IFC ─────────────────────
// En producción, aquí se leerían los primeros bytes del archivo
// para extraer ISO-10303-21 HEADER; SECTION

const now = new Date().toISOString();
const fileId = `IFC-${Date.now()}`;

// ─── 3. Validaciones IFC 4.3 (buildingSMART) ───────────────────
const validDisciplines = [
  'Arquitectura', 'Estructura', 'MEP',
  'Civil', 'Infraestructura', 'Prefabricado'
];

const validPhases = [
  'Conceptual', 'Diseño', 'Construcción',
  'Operación', 'Demolición'
];

const validFormats = ['.ifc', '.ifcxml', '.ifczip'];

const warnings = [];

if (!validDisciplines.includes(discipline)) {
  warnings.push(`Disciplina '${discipline}' no es estándar IFC. Use: ${validDisciplines.join(', ')}`);
}

if (!validPhases.includes(phase)) {
  warnings.push(`Fase '${phase}' no reconocida. Use: ${validPhases.join(', ')}`);
}

// ─── 4. Preparar payload de metadatos ─────────────────────────
return {
  json: {
    // Identificación
    file_id: fileId,
    timestamp: now,
    status: 'pending_validation',

    // Datos del proyecto
    project_name: projectName,
    description: description,
    discipline: discipline,
    phase: phase,
    uploaded_by: uploadedBy,

    // Metadatos IFC (se completarán con parser real)
    ifc_version: 'IFC4.3',
    ifc_schema: 'IFC4X3_ADD2',
    iso_standard: 'ISO 16739-1:2024',

    // Estado de validaciones
    warnings: warnings,
    validation_passed: warnings.length === 0,

    // URLs de referencia buildingSMART
    bsi_validation_url: 'https://www.buildingsmart.org/users/services/ifc-validation-service/',
    bsi_docs_url: 'https://ifc43-docs.standards.buildingsmart.org/'
  }
};

// ============================================================
// NODO — PARSER IFC (Extracción real de entidades)
// Soporta: IFC 2x3, IFC 4, IFC 4.3
// ============================================================

const item = $input.item;
const metadata = item.json;

// En producción: usar biblioteca IfcOpenShell o similar
// Aquí simulamos la extracción de entidades IFC clave

// Entidades IFC principales a extraer:
const ifcEntities = {
  // 4D — Cronograma
  schedule: {
    entity: 'IfcWorkSchedule',
    tasks: 'IfcTask',
    taskTime: 'IfcTaskTime',
    sequence: 'IfcRelSequence',
    product_assignment: 'IfcRelAssignsToProcess'
  },
  // 5D — Costos
  cost: {
    entity: 'IfcCostSchedule',
    items: 'IfcCostItem',
    value: 'IfcCostValue',
    quantity: 'IfcElementQuantity'
  },
  // Elementos constructivos clave
  elements: [
    'IfcWall', 'IfcSlab', 'IfcBeam', 'IfcColumn',
    'IfcDoor', 'IfcWindow', 'IfcStair', 'IfcRoof',
    'IfcSpace', 'IfcBuildingStorey', 'IfcBuilding',
    'IfcSite', 'IfcProject'
  ],
  // Propiedades
  properties: [
    'Pset_WallCommon', 'Pset_SlabCommon',
    'Pset_BeamCommon', 'Pset_ColumnCommon',
    'Pset_BuildingCommon', 'Pset_SpaceCommon'
  ]
};

// Propiedades 4D/5D extraídas (simulación)
const extracted = {
  global_id: `{${metadata.file_id}}`,
  project_entity: {
    type: 'IfcProject',
    name: metadata.project_name,
    description: metadata.description,
    phase: metadata.phase
  },
  element_count: 0,       // Se llenaría con parser real
  storey_count: 0,        // IfcBuildingStorey count
  space_count: 0,         // IfcSpace count
  schedule_found: false,  // IfcWorkSchedule present
  cost_found: false,      // IfcCostSchedule present
  has_4d: false,
  has_5d: false,

  // IFC Properties Sets detectados
  property_sets: [],

  // Compliance buildingSMART
  mvd_compliance: 'Reference View',  // Model View Definition
  validation_service: 'https://www.buildingsmart.org/users/services/ifc-validation-service/'
};

return {
  json: {
    ...metadata,
    ...extracted,
    ifc_entities_schema: ifcEntities,
    parser_status: 'completed',
    ready_for_storage: true
  }
};

// ============================================================
// NODO — CONSTRUIR REGISTRO PARA NOTION DATABASE
// Según el schema de la DB en Notion del BIM-Orchestrator
// ============================================================

const item = $input.item;
const data = item.json;
const now = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

// Construir payload para la API de Notion
// Mapeo de campos del DB de Notion detectado en la URL
const notionPagePayload = {
  parent: {
    database_id: 'NOTION_DATABASE_ID'  // Reemplazar con ID real
  },
  icon: {
    type: 'emoji',
    emoji: '🏗️'
  },
  properties: {
    // Título principal
    'Nombre': {
      title: [{
        text: { content: data.project_name }
      }]
    },
    // ID del archivo IFC
    'File ID': {
      rich_text: [{
        text: { content: data.file_id }
      }]
    },
    // Versión IFC
    'IFC Version': {
      select: { name: data.ifc_version || 'IFC4.3' }
    },
    // Disciplina
    'Disciplina': {
      select: { name: data.discipline || 'Arquitectura' }
    },
    // Fase
    'Fase': {
      select: { name: data.phase || 'Diseño' }
    },
    // Estado
    'Estado': {
      status: { name: data.parser_status === 'completed' ? 'Procesado' : 'Pendiente' }
    },
    // Fecha de subida
    'Fecha Subida': {
      date: { start: now }
    },
    // Tiene 4D
    '4D (Cronograma)': {
      checkbox: data.has_4d || false
    },
    // Tiene 5D
    '5D (Costos)': {
      checkbox: data.has_5d || false
    },
    // Norma ISO
    'Norma ISO': {
      rich_text: [{
        text: { content: data.iso_standard || 'ISO 16739-1:2024' }
      }]
    },
    // Subido por
    'Subido por': {
      rich_text: [{
        text: { content: data.uploaded_by || 'Sistema' }
      }]
    },
    // Descripción
    'Descripción': {
      rich_text: [{
        text: { content: data.description || '' }
      }]
    },
    // URL de validación buildingSMART
    'Validación bSI': {
      url: data.validation_service || 'https://www.buildingsmart.org/users/services/ifc-validation-service/'
    }
  }
};

return {
  json: {
    notion_payload: notionPagePayload,
    source_data: data,
    ready: true
  }
};

