// Respuesta exitosa al cliente
const data = $('parse-ifc-entities').item.json;
const notionPage = $('create-notion-page').item.json;

return {
  json: {
    success: true,
    message: '✅ Archivo IFC procesado y registrado exitosamente',
    file_id: data.file_id,
    notion_page_url: `https://notion.so/${(notionPage.id || '').replace(/-/g, '')}`,
    ifc_version: data.ifc_version,
    iso_standard: data.iso_standard,
    project: data.project_name,
    discipline: data.discipline,
    phase: data.phase,
    has_4d: data.has_4d,
    has_5d: data.has_5d,
    validation: {
      passed: data.validation_passed,
      warnings: data.warnings || []
    },
    bsi_resources: {
      validation_service: 'https://www.buildingsmart.org/users/services/ifc-validation-service/',
      ifc_docs: 'https://ifc43-docs.standards.buildingsmart.org/',
      ifc_formats: 'https://technical.buildingsmart.org/standards/ifc/ifc-formats/'
    },
    timestamp: new Date().toISOString()
  }
};

// Respuesta de error con warnings
const data = $input.item.json;

return {
  json: {
    success: false,
    message: '⚠️ El archivo IFC no pasó la validación',
    file_id: data.file_id,
    errors: data.warnings || ['Error de validación desconocido'],
    validation: {
      passed: false,
      warnings: data.warnings || []
    },
    help: {
      ifc_standard: 'IFC 4.3 (ISO 16739-1:2024)',
      validation_service: 'https://www.buildingsmart.org/users/services/ifc-validation-service/',
      valid_disciplines: ['Arquitectura', 'Estructura', 'MEP', 'Civil', 'Infraestructura', 'Prefabricado'],
      valid_phases: ['Conceptual', 'Diseño', 'Construcción', 'Operación', 'Demolición'],
      valid_formats: ['.ifc', '.ifcxml', '.ifczip']
    },
    timestamp: new Date().toISOString()
  }
};
